PART = 'def add_cone(\n    name,\n    location,\n    scale,\n    material,\n    rotation=(0.0, 0.0, 0.0),\n    vertices=20,\n):\n    bpy.ops.mesh.primitive_cone_add(\n        vertices=vertices,\n        radius1=1.0,\n        radius2=0.0,\n        depth=2.0,\n        location=location,\n        rotation=rotation,\n    )\n    obj = bpy.context.active_object\n    obj.name = name\n    obj.scale = scale\n    bpy.ops.object.transform_apply(location=False, rotation=False, scale=True)\n    obj.data.materials.append(material)\n    smooth_object(obj)\n    return obj\n\n\ndef add_cylinder_between(name, start, end, radius, material, vertices=16):\n    start_v = Vector(start)\n    end_v = Vector(end)\n    direction = end_v - start_v\n    length = max(direction.length, 0.001)\n    midpoint = (start_v + end_v) * 0.5\n    bpy.ops.mesh.primitive_cylinder_add(\n        vertices=vertices,\n        radius=radius,\n        depth=length,\n        location=midpoint,\n    )\n    obj = bpy.context.active_object\n    obj.name = name\n    obj.rotation_mode = "QUATERNION"\n    obj.rotation_quaternion = direction.to_track_quat("Z", "Y")\n    obj.rotation_mode = "XYZ"\n    obj.data.materials.append(material)\n    smooth_object(obj)\n    return obj\n\n\ndef add_torus(name, location, major_radius, minor_radius, material, scale=(1.0, 1.0, 1.0)):\n    bpy.ops.mesh.primitive_torus_add(\n        major_segments=24,\n        minor_segments=8,\n        major_radius=major_radius,\n        minor_radius=minor_radius,\n        location=location,\n    )\n    obj = bpy.context.active_object\n    obj.name = name\n    obj.scale = scale\n    bpy.ops.object.transform_apply(location=False, rotation=False, scale=True)\n    obj.data.materials.append(material)\n    smooth_object(obj)\n    return obj\n\n\ndef add_loincloth(name, material):\n    vertices = [\n        (-0.52, -0.48, 1.02),\n        (0.52, -0.48, 1.02),\n        (0.0, -0.58, 0.42),\n        (-0.52, -0.36, 1.02),\n        (0.52, -0.36, 1.02),\n        (0.0, -0.43, 0.42),\n    ]\n    faces = [\n        (0, 1, 2),\n        (3, 5, 4),\n        (0, 3, 4, 1),\n        (1, 4, 5, 2),\n        (2, 5, 3, 0),\n    ]\n    mesh = bpy.data.meshes.new(f"{name}_Mesh")\n    mesh.from_pydata(vertices, [], faces)\n    mesh.update()\n    obj = bpy.data.objects.new(name, mesh)\n    bpy.context.collection.objects.link(obj)\n    obj.data.materials.append(material)\n    bevel = obj.modifiers.new(name="Cloth soft edge", type="BEVEL")\n    bevel.width = 0.04\n    bevel.segments = 2\n    return obj\n\n\ndef parent_to_bone(obj, armature, bone_name: str) -> None:\n    world_matrix = obj.matrix_world.copy()\n    obj.parent = armature\n    obj.parent_type = "BONE"\n    obj.parent_bone = bone_name\n    obj.matrix_world = world_matrix\n\n\ndef create_armature():\n    bpy.ops.object.armature_add(enter_editmode=True, location=(0.0, 0.0, 0.0))\n    rig = bpy.context.active_object\n    rig.name = "OyenPurba_Rig"\n    rig.data.name = "OyenPurba_Armature"\n    rig.show_in_front = True\n    rig.data.display_type = "OCTAHEDRAL"\n\n    edit_bones = rig.data.edit_bones\n    for bone in list(edit_bones):\n'